import reactor.core.publisher.Flux;
import reactor.core.publisher.Mono;
import java.time.Duration;
import java.util.List;

public class ReactorDemo {
    public static void main(String[] args) throws InterruptedException {

        // ── Mono: 0 or 1 element ───────────────────────────────────
        Mono<String> greeting = Mono.just("Hello, Reactor!");
        greeting.subscribe(System.out::println); // Hello, Reactor!

        Mono<String> empty = Mono.empty();
        empty.subscribe(
            val   -> System.out.println("Got: " + val),
            err   -> System.err.println("Error: " + err),
            ()    -> System.out.println("Mono completed with no value")
        );

        // ── Flux: 0 to N elements ──────────────────────────────────
        Flux<Integer> numbers = Flux.just(1, 2, 3, 4, 5);

        numbers
            .filter(n -> n % 2 == 0)        // 2, 4
            .map(n -> n * n)                 // 4, 16
            .subscribe(System.out::println); // 4 then 16

        // ── FlatMap: async chaining ────────────────────────────────
        Flux<String> users = Flux.just("alice", "bob", "carol");
        users
            .flatMap(name -> fetchGreeting(name))  // simulated async
            .subscribe(System.out::println);

        // ── Collect Flux → List ────────────────────────────────────
        List<Integer> list = Flux.range(1, 5)
            .collectList()
            .block(); // block() is OK in tests/main, not in reactive controllers
        System.out.println(list); // [1, 2, 3, 4, 5]

        // ── Zip: combine two streams ───────────────────────────────
        Mono<String> firstName = Mono.just("John");
        Mono<String> lastName  = Mono.just("Doe");
        firstName.zipWith(lastName, (f, l) -> f + " " + l)
            .subscribe(System.out::println); // John Doe

        // ── Error handling ─────────────────────────────────────────
        Mono<Integer> risky = Mono.error(new RuntimeException("DB down"));
        risky
            .onErrorReturn(-1)  // fallback value
            .subscribe(System.out::println); // -1

        // ── DoOnNext: side effects (logging) ───────────────────────
        Flux.just("a", "b", "c")
            .doOnNext(s -> System.out.println("Processing: " + s))
            .map(String::toUpperCase)
            .subscribe(System.out::println);

        Thread.sleep(500); // wait for async ops
    }

    // Simulates an async operation returning a Mono
    static Mono<String> fetchGreeting(String name) {
        return Mono.just("Hello, " + name + "!");
    }
}

