import reactor.core.publisher.Mono;
import java.util.*;

public class Q3 {
    static Mono<String> safeSqrt(int n) {
        return Mono.fromCallable(() -> {
            if (n <= 0) throw new ArithmeticException("sqrt of non-positive");
            return String.format("%.2f", Math.sqrt(n));
        }).onErrorReturn("ERR");
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        while (sc.hasNextInt()) {
            int n = sc.nextInt();
            safeSqrt(n).subscribe(System.out::println);
        }
    }
}
